module top(input clk, input rst_n, input in, output reg detected);
  // Write code here
endmodule

solution_code:
module top(input clk, input rst_n, input in, output reg detected);
  localparam S0=2'd0, S1=2'd1, S10=2'd2, S101=2'd3;
  reg [1:0] st, nx;
  always @(posedge clk or negedge rst_n)
    if (!rst_n) st <= S0; else st <= nx;
  always @(*) begin
    nx = st; detected = 1'b0;
    case (st)
      S0:   nx = in ? S1   : S0;
      S1:   nx = in ? S1   : S10;
      S10:  nx = in ? S101 : S0;
      S101: begin nx = in ? S1 : S10; detected = in; end
    endcase
  end
endmodule

