  // Write code here
endmodule

solution_code:
module top(input logic clk, rst_n, input logic [3:0] req, output logic [3:0] gnt);
  logic [1:0] ptr;
  always_ff @(posedge clk or negedge rst_n)
    if (!rst_n) ptr <= 2'd0;
    else if (|gnt) begin
      casez (gnt)
        4'b0001: ptr <= 2'd1;
        4'b0010: ptr <= 2'd2;
        4'b0100: ptr <= 2'd3;
        default: ptr <= 2'd0;
      endcase
    end
  always_comb begin
    gnt = 4'b0000;
    for (int i = 0; i < 4; i++) begin
      automatic int idx = (ptr + i) & 2'b11;
      if (req[idx]) begin gnt[idx] = 1'b1; break; end
    end
  end
endmodule

