solution_code:
module top(input logic clk, rst_n, output logic pulse);
  typedef enum logic [2:0] {S0=3'b001, S1=3'b010, S2=3'b100} st_t;
  st_t st;
  always_ff @(posedge clk or negedge rst_n)
    if (!rst_n) st <= S0;
    else unique case (st)
      S0: st <= S1;
      S1: st <= S2;
      S2: st <= S0;
      default: st <= S0;
    endcase
  assign pulse = (st == S2);
endmodule

