solution_code:
module top(input pclk, input presetn, input psel, input penable, input pwrite, input [31:0] paddr, input [31:0] pwdata, output reg [31:0] prdata, output pready);
  reg [31:0] datareg;
  assign pready = 1'b1;
  always @(posedge pclk or negedge presetn) begin
    if (!presetn) datareg <= 32'd0;
    else if (psel && penable && pwrite) datareg <= pwdata;
  end
  always @(*) prdata = (psel && !pwrite) ? datareg : 32'd0;
endmodule
